from dataclasses import dataclass
from enum import Enum
import random

class RouterTarget(str, Enum):
    LEGACY  = "legacy"
    NEW     = "new"
    SHADOW  = "shadow"  # new path runs in parallel for logging only; legacy response served

@dataclass
class StranglerFigRouter:
    """
    Routes requests between legacy and new architecture implementations.
    Traffic percentage to new path increases incrementally during migration.
    """
    new_path_percentage: float = 0.0    # 0.0 = all traffic to legacy; 1.0 = all to new
    shadow_mode: bool = True            # if True, new path runs silently for comparison

    def route(self, request_id: str) -> RouterTarget:
        """
        Deterministic routing based on request_id hash ensures the same
        request consistently routes to the same path during gradual rollout.
        """
        # Hash last 4 hex digits of request ID for deterministic assignment
        bucket = int(request_id[-4:], 16) / 65535 if request_id else random.random()

        if bucket < self.new_path_percentage:
            return RouterTarget.NEW
        if self.shadow_mode:
            return RouterTarget.SHADOW
        return RouterTarget.LEGACY

    def increase_traffic(self, increment: float = 0.05) -> None:
        """Increase new-path traffic by increment (default 5%)."""
        self.new_path_percentage = min(1.0, self.new_path_percentage + increment)

    def status(self) -> str:
        if self.new_path_percentage >= 1.0:
            return "MIGRATION COMPLETE: 100% traffic on new path"
        if self.shadow_mode and self.new_path_percentage == 0.0:
            return f"SHADOW MODE: new path running silently; 0% live traffic"
        return (
            f"IN PROGRESS: {self.new_path_percentage:.0%} on new path"
            + (" (shadow mode active)" if self.shadow_mode else "")
        )

from dataclasses import dataclass, field
from datetime import datetime

@dataclass
class ParallelRunEntry:
    request_id: str
    timestamp: datetime
    input_hash: str          # hash of the input prompt; for dedup
    legacy_output_summary: str   # not the full response; a summary or hash for comparison
    new_output_summary: str
    outputs_equivalent: bool | None = None  # assessed by an automated comparison function
    human_reviewed: bool = False

    def needs_review(self) -> bool:
        return self.outputs_equivalent is False and not self.human_reviewed

@dataclass
class ParallelRunLog:
    migration_id: str
    entries: list[ParallelRunEntry] = field(default_factory=list)

    def add(self, entry: ParallelRunEntry) -> None:
        self.entries.append(entry)

    def divergence_rate(self) -> float:
        assessed = [e for e in self.entries if e.outputs_equivalent is not None]
        if not assessed:
            return 0.0
        divergent = [e for e in assessed if not e.outputs_equivalent]
        return len(divergent) / len(assessed)

    def review_queue(self) -> list[ParallelRunEntry]:
        return [e for e in self.entries if e.needs_review()]

    def migration_readiness(self, max_divergence: float = 0.05) -> str:
        rate = self.divergence_rate()
        queue_size = len(self.review_queue())
        if rate <= max_divergence and queue_size == 0:
            return f"READY: divergence {rate:.1%} within threshold; review queue empty"
        issues = []
        if rate > max_divergence:
            issues.append(f"divergence {rate:.1%} exceeds {max_divergence:.0%} threshold")
        if queue_size > 0:
            issues.append(f"{queue_size} unreviewed divergent pairs")
        return "NOT READY: " + "; ".join(issues)

from dataclasses import dataclass, field
from enum import Enum

class ModelPinStrategy(str, Enum):
    PINNED          = "pinned"          # explicit model-id including date/version suffix
    ALIAS_STABLE    = "alias_stable"    # e.g. "claude-3-5-sonnet-20241022" (Anthropic's stable alias)
    ALIAS_LATEST    = "alias_latest"    # e.g. "claude-sonnet-4" (may change without notice)

@dataclass
class ModelVersionPolicy:
    integration_name: str
    current_model_id: str
    pin_strategy: ModelPinStrategy
    golden_set_validated_against: str  # model version the golden set was last validated against
    upgrade_gate_required: bool        # True = cannot upgrade without running upgrade test suite
    last_upgrade_date: str             # ISO date of last model change

    def is_out_of_date_with_golden_set(self) -> bool:
        return self.current_model_id != self.golden_set_validated_against

    def upgrade_risk_level(self) -> str:
        if self.pin_strategy == ModelPinStrategy.ALIAS_LATEST:
            return "HIGH: model may change without any action by the team"
        if self.pin_strategy == ModelPinStrategy.ALIAS_STABLE:
            return "MEDIUM: model is stable but may change when Anthropic updates the alias"
        return "LOW: explicitly pinned; upgrade only on deliberate action"

    def policy_summary(self) -> str:
        lines = [
            f"Integration: {self.integration_name}",
            f"Model: {self.current_model_id} ({self.pin_strategy.value})",
            f"Upgrade gate: {'required' if self.upgrade_gate_required else 'not required'}",
            f"Upgrade risk: {self.upgrade_risk_level()}",
        ]
        if self.is_out_of_date_with_golden_set():
            lines.append(
                f"WARNING: golden set validated against {self.golden_set_validated_against}, "
                f"not current model {self.current_model_id}"
            )
        return "\n".join(lines)

from dataclasses import dataclass, field
from datetime import date

@dataclass
class AIArchitectureDecision:
    decision_id: str              # e.g. "AIADR-007"
    title: str
    date_decided: date
    decision_maker: str

    # The decision itself
    boundary_question: str        # what architectural question does this answer?
    options_considered: list[str]
    chosen_option: str
    rationale: str

    # AI-specific fields
    prompt_implications: str      # how this decision constrains or enables prompt design
    model_upgrade_sensitivity: str  # how likely a model upgrade is to require revisiting this
    revisit_trigger: str          # what event or condition would invalidate this decision

    def adr_document(self) -> str:
        options_str = "\n".join(f"- {o}" for o in self.options_considered)
        return f"""## {self.decision_id}: {self.title}

Date: {self.date_decided} | Decided by: {self.decision_maker}

### Architectural Question
{self.boundary_question}

### Options Considered
{options_str}

### Decision
{self.chosen_option}

### Rationale
{self.rationale}

### Prompt Design Implications
{self.prompt_implications}

### Model Upgrade Sensitivity
{self.model_upgrade_sensitivity}

### Revisit Trigger
{self.revisit_trigger}
"""
